<template>
    <div class="container-fluid p-0"   :style="!isChartHistory ? { overflow: 'auto', minHeight: '494px', maxHeight: '600px', maxWidth: '1168px' } : null" id="divflowchartscroll">
    <input type="hidden" :value="showFromInvoice" />
    <input type="hidden" :value="showHistory" />
    <div v-if="flowData.length > 0" chart-id="RflowChartNew"  style="width: 1820px; min-width: 1400px;">
      <RBillingFlowChart :data="flowData"  chart-class="outer" :isBillingType="isBillingType"/>
    </div>
    <div v-else class="text-danger text-center" style="padding-top: 50%;">No Data Found</div>
  </div>
</template>
<script>
import RBillingFlowChart from '../../../views/BillingRule/ConfigurationComponent/RBillingFlowChart.vue';
import DataService from "../../../services/DataService";
export default {
  name: 'FlowChartWrapper',
  components: { RBillingFlowChart },
  props: {
    CONFIGURATION_ID: {
      type:Number,
      required: false
    },
    isChartHistory:{ 
      type: Boolean,
      required: false
    },
    clientId: {
      type:Number,
      required: false
    },
    showHistory:{
      type:String,
      required: false
    }
    
  },
  data() {
    return {
      flowData: [],
      showHistory: '0',
      showFromInvoice: '1',
      isBillingType:false
      
    };
  },
  created: async function () {
    var vm = this;
    this.isBillingType = localStorage.getItem("billingType") === "USIC";
    if (vm.showFromInvoice === '1') {
      await vm.fetchFlowData(vm.CONFIGURATION_ID, vm.showHistory);
    }
  },
  methods: {
    fetchFlowData: async function (CONFIGURATION_ID, showHistory) {
      var vm = this;
      var params = "configId=" + CONFIGURATION_ID + "&clientId="+ this.clientId +"&includeParentNode=true&showHistory=" + showHistory +"&isBillingType="+ this.isBillingType;
      const response = await DataService.ShowFlowchartNew(params);
      if (response && response.data && response.data.length > 0) {
        this.flowData = response.data;
      }
    }
    
  }
};
</script>
<style scoped>

#RflowChartNew {
width: unset !important;

}


</style>